INSERT INTO services (slug, tag, title, short_desc, headline, accent, description, features, ideal, price, delay, image, sort_order, active) VALUES ('landing-page', 'Conversion', 'Landing Page', 'Une page qui convertit vos visiteurs en clients.', 'Une page qui convertit vos visiteurs en clients', 'convertit', 'Une page unique, rapide et percutante, construite autour d''un seul objectif : transformer vos visiteurs en contacts ou en ventes. Idéale pour lancer un produit, une campagne publicitaire ou valider une idée.', '["Design sur-mesure aligné à votre marque","Textes optimisés pour la conversion","Formulaire de contact / WhatsApp intégré","Nom de domaine + hébergement 1 an","Certificat SSL (https) + optimisation vitesse","Référencement Google de base (SEO)"]', 'Lancements produit · Campagnes pub · Événements · Indépendants', '200 000 FCFA', '≈ 2 semaines', '/images/service-landing.jpg', 0, 1);
INSERT INTO services (slug, tag, title, short_desc, headline, accent, description, features, ideal, price, delay, image, sort_order, active) VALUES ('e-commerce', 'Vente en ligne', 'Site E-commerce', 'Vendez en ligne, simplement et en toute sécurité.', 'Vendez en ligne, simplement et en toute sécurité', 'vendez', 'Une boutique complète pour vendre 24h/24 : catalogue produits, panier, paiement Mobile Money et cartes bancaires, gestion des commandes. On vous forme pour être 100% autonome.', '["Catalogue produits illimité + recherche","Paiement MTN MoMo, Orange Money & cartes","Gestion des commandes et des stocks","Design, dev, domaine & hébergement 1 an","Sécurité SSL + protection des données clients","Formation à la gestion + support 3 mois"]', 'Boutiques · Marques · Grossistes · Restaurants (commande en ligne)', '500 000 FCFA', '≈ 4-6 semaines', '/images/service-ecommerce.jpg', 1, 1);
INSERT INTO services (slug, tag, title, short_desc, headline, accent, description, features, ideal, price, delay, image, sort_order, active) VALUES ('blog-vitrine', 'Visibilité', 'Blog / Vitrine', 'Racontez votre histoire, gagnez en visibilité.', 'Racontez votre histoire, gagnez en visibilité', 'histoire', 'Un site élégant qui présente votre activité, vos valeurs et vos réalisations. Avec un espace blog pour publier vos actualités et améliorer votre position sur Google mois après mois.', '["Pages : accueil, à propos, services, contact","Espace blog administrable sans coder","Galerie photos / portfolio","Domaine + hébergement 1 an + SSL","SEO de base + Google Business Profile","Formation à la publication d''articles"]', 'PME · Cabinets · Artisans · ONG · Professions libérales', '300 000 FCFA', '≈ 3 semaines', '/images/service-blog.jpg', 2, 1);
INSERT INTO services (slug, tag, title, short_desc, headline, accent, description, features, ideal, price, delay, image, sort_order, active) VALUES ('saas', 'Produit', 'SaaS', 'Votre logiciel en ligne, conçu pour grandir avec vous.', 'Votre logiciel en ligne, conçu pour grandir avec vous', 'grandir', 'De l''idée au produit : on conçoit et développe votre logiciel en ligne (abonnements, tableaux de bord, multi-utilisateurs). Architecture solide, pensée pour évoluer sans tout reconstruire.', '["Cadrage produit & maquettes interactives","Développement MVP en cycles courts","Comptes utilisateurs, rôles & abonnements","Tableau de bord & statistiques","Infrastructure cloud sécurisée & sauvegardes","Maintenance évolutive & accompagnement"]', 'Startups · Éditeurs · Entreprises qui automatisent un métier', 'Sur devis', 'MVP ≈ 6-10 semaines', '/images/service-saas.jpg', 3, 1);
INSERT INTO services (slug, tag, title, short_desc, headline, accent, description, features, ideal, price, delay, image, sort_order, active) VALUES ('application', 'Web & mobile', 'Application', 'Web ou mobile, pensée pour vos utilisateurs.', 'Web ou mobile, pensée pour vos utilisateurs', 'utilisateurs', 'Application web ou mobile (Android / iOS) avec une vraie démarche UX : simple à prendre en main, rapide même en connexion faible, et adaptée aux usages locaux.', '["Ateliers UX & prototypes cliquables","App web (PWA) ou mobile native/hybride","Mode hors-ligne & performance 3G","Notifications push & Mobile Money si besoin","Publication Play Store / App Store","Suivi, correctifs & évolutions"]', 'Services de livraison · Fintech · Éducation · Communautés', 'Sur devis', '≈ 8-12 semaines', '/images/service-app.jpg', 4, 1);
INSERT INTO services (slug, tag, title, short_desc, headline, accent, description, features, ideal, price, delay, image, sort_order, active) VALUES ('sur-mesure', 'Entreprises', 'Sur-mesure', 'Une solution digitale taillée pour votre entreprise.', 'Une solution digitale taillée pour votre entreprise', 'taillée', 'Outil de gestion interne, plateforme métier, intranet, automatisation... On analyse vos processus et on construit exactement l''outil qu''il vous faut — pas un logiciel générique de plus.', '["Audit gratuit de vos processus","Cahier des charges co-construit","Intégration à vos outils existants","Formation complète de vos équipes","Hébergement sécurisé ou sur vos serveurs","Contrat de maintenance dédié"]', 'PME & grandes entreprises · Administrations · Écoles · Cliniques', 'Sur devis', 'Selon projet', '/images/service-custom.jpg', 5, 1);
