INSERT INTO faqs (question, answer, sort_order, active) VALUES ('Le prix affiché est-il vraiment tout compris ?', 'Oui. Design, développement, nom de domaine, hébergement la première année, certificat SSL et mise en ligne sont inclus. La seule dépense future est le renouvellement domaine + hébergement (à partir de la 2e année), annoncé dès le devis.', 0, 1);
INSERT INTO faqs (question, answer, sort_order, active) VALUES ('Puis-je payer en plusieurs fois ?', 'Oui. En général : un acompte au démarrage, un paiement à la validation du design, et le solde à la livraison. On s''adapte à votre trésorerie — parlons-en simplement.', 1, 1);
INSERT INTO faqs (question, answer, sort_order, active) VALUES ('Combien de temps pour avoir mon site en ligne ?', 'Une landing page est livrée en 2 semaines environ, un site vitrine en 3 semaines, un e-commerce en 4 à 6 semaines. Le délai exact est fixé dans le devis et on s''y tient.', 2, 1);
INSERT INTO faqs (question, answer, sort_order, active) VALUES ('Pourrai-je modifier mon site moi-même ?', 'Oui. On vous livre un espace d''administration simple et on vous forme (en visio ou à Douala). Textes, photos, articles, produits : vous êtes autonome. Et si besoin, notre support reste disponible.', 3, 1);
INSERT INTO faqs (question, answer, sort_order, active) VALUES ('Proposez-vous le paiement Mobile Money sur les boutiques ?', 'Absolument — c''est même indispensable au Cameroun. On intègre MTN Mobile Money, Orange Money et les cartes bancaires selon vos besoins.', 4, 1);
INSERT INTO faqs (question, answer, sort_order, active) VALUES ('Que se passe-t-il après la livraison ?', 'Chaque pack inclut une période de support (corrections, questions, petites retouches). Ensuite, vous pouvez continuer en toute autonomie ou souscrire une maintenance mensuelle légère.', 5, 1);
INSERT INTO posts (title, category, date, read_time, excerpt, image, featured, sort_order, active) VALUES ('Mobile Money sur votre site : pourquoi c''est indispensable au Cameroun', 'Conseils', '28 juin 2026', '5 min', 'MTN MoMo et Orange Money représentent l''écrasante majorité des paiements en ligne au Cameroun. Si votre boutique n''accepte que la carte bancaire, vous perdez des ventes chaque jour. Voici comment intégrer le paiement mobile, combien ça coûte et les pièges à éviter.', '/images/blog-1.jpg', 1, 0, 1);
INSERT INTO posts (title, category, date, read_time, excerpt, image, featured, sort_order, active) VALUES ('Combien coûte vraiment un site web professionnel en 2026 ?', 'Guide', '15 juin 2026', '7 min', 'Domaine, hébergement, design, maintenance : on décompose tout, sans langue de bois.', '/images/blog-2.jpg', 0, 1, 1);
INSERT INTO posts (title, category, date, read_time, excerpt, image, featured, sort_order, active) VALUES ('De la boutique de quartier à 100 commandes en ligne par mois', 'Success story', '2 juin 2026', '4 min', 'Comment un commerçant de Douala a digitalisé son activité avec un simple pack e-commerce.', '/images/blog-3.jpg', 0, 2, 1);
INSERT INTO posts (title, category, date, read_time, excerpt, image, featured, sort_order, active) VALUES ('5 signes que votre entreprise a besoin d''un site web (maintenant)', 'Conseils', '20 mai 2026', '6 min', 'Vos clients vous cherchent sur Google et trouvent... vos concurrents. On fait le point.', '/images/service-blog.jpg', 0, 3, 1);
INSERT INTO posts (title, category, date, read_time, excerpt, image, featured, sort_order, active) VALUES ('SaaS, application, site web : quelle solution pour votre idée ?', 'Guide', '8 mai 2026', '8 min', 'Les différences expliquées simplement, avec des exemples et des budgets réalistes.', '/images/service-saas.jpg', 0, 4, 1);
