INSERT INTO process_steps (num, title, description, sort_order, active) VALUES ('01', 'Échange', 'On écoute votre projet, vos objectifs et votre budget. Premier rendez-vous gratuit, en ligne ou à Douala.', 0, 1);
INSERT INTO process_steps (num, title, description, sort_order, active) VALUES ('02', 'Devis clair', 'Sous 48h, vous recevez une proposition détaillée : prix fixe, délais, livrables. Zéro frais caché.', 1, 1);
INSERT INTO process_steps (num, title, description, sort_order, active) VALUES ('03', 'Design & Dev', 'On conçoit, vous validez à chaque étape. Vous suivez l''avancement en temps réel, sans jargon technique.', 2, 1);
INSERT INTO process_steps (num, title, description, sort_order, active) VALUES ('04', 'Livraison & suivi', 'Mise en ligne, formation à la prise en main et support continu. On reste à vos côtés après la livraison.', 3, 1);
